const tickerRaw   = $('Fetch BTC').first().json;
const signalsRaw  = $('Read Signals').first().json;
const outcomesRaw = $('Read Outcomes').first().json;

const r      = (tickerRaw && tickerRaw.result) ? tickerRaw.result : {};
const k      = Object.keys(r)[0];
const t      = r[k] || {};
const price    = t.c ? parseFloat(t.c[0]) : 0;
const openDay  = t.o ? parseFloat(t.o)    : price;
const high24   = t.h ? parseFloat(t.h[1]) : price;
const low24    = t.l ? parseFloat(t.l[1]) : price;
const vwap24   = t.p ? parseFloat(t.p[1]) : price;
const vol24btc = t.v ? parseFloat(t.v[1]) : 0;
const vol24usd = Math.round(vol24btc * vwap24 / 1e6);
const trades24 = t.t ? t.t[1] : 0;
const bid      = t.b ? parseFloat(t.b[0]) : price;
const ask      = t.a ? parseFloat(t.a[0]) : price;
const spread   = Math.abs(ask - bid).toFixed(2);
const change24h = openDay > 0 ? ((price - openDay) / openDay) * 100 : 0;
const c24Str   = (change24h >= 0 ? '+' : '') + change24h.toFixed(2) + '%';
const rangePos  = (high24 > low24) ? Math.round(((price - low24) / (high24 - low24)) * 100) : 50;

const memories = (signalsRaw && signalsRaw.memories) ? signalsRaw.memories : [];
const signals = [];
for (const m of memories.slice(0, 10)) {
  const c   = m.content || '';
  const dir  = (c.match(/TRADE SIGNAL[^:]*:\s*(BUY|SELL|WAIT)/) || [])[1];
  const px   = (c.match(/@\s*\$(\d+)/)                          || [])[1];
  const conf = (c.match(/Conf[idence]*[:\s]+([\d.]+)%/)         || [])[1];
  const rsi  = (c.match(/RSI[:\s]+([\d.]+)/)                    || [])[1];
  const reg  = (c.match(/Regime[:\s]+(\S+?)(?:\s|$|\|)/)        || [])[1];
  const quor = (c.match(/Quorum[:\s]+(\d+)/)                    || [])[1];
  const nts  = (c.match(/No.?Trade[:\s]+([\d.]+)/)              || [])[1];
  const ts   = m.created_at ? m.created_at.slice(11, 16) : '?';
  if (!dir) continue;
  signals.push({ dir, px: px||'?', conf: conf||'?', rsi: rsi||'?', reg: reg||'?', quor: quor||'?', nts: nts||'?', ts });
}
const last     = signals[0] || {};
const confNum  = parseFloat(last.conf) || 0;
const buyCnt   = signals.filter(s => s.dir === 'BUY').length;
const sellCnt  = signals.filter(s => s.dir === 'SELL').length;
const waitCnt  = signals.filter(s => s.dir === 'WAIT').length;

const outMems = (outcomesRaw && outcomesRaw.memories) ? outcomesRaw.memories : [];
let hitRate = -1, hitCorrect = 0, hitIncorrect = 0, hitTotal = 0, hitAvgConf = 0;
for (const o of outMems) {
  const c   = o.content || '';
  const hr  = (c.match(/Hit Rate[:\s]+([\d.]+)%/) || [])[1];
  if (hr) {
    hitRate      = parseInt(hr);
    hitCorrect   = parseInt((c.match(/Correct[:\s]+(\d+)/)          || [])[1] || 0);
    hitIncorrect = parseInt((c.match(/Incorrect[:\s]+(\d+)/)        || [])[1] || 0);
    hitTotal     = hitCorrect + hitIncorrect;
    hitAvgConf   = parseFloat((c.match(/Avg Confidence[:\s]+([\d.]+)%/) || [])[1] || 0);
    break;
  }
}

const fmt    = n => Math.round(n).toLocaleString('en-US');
const fmtK   = n => n >= 1000 ? (n / 1000).toFixed(1) + 'K' : String(n);
const pCol   = change24h >= 0 ? '#00d97e' : '#ff4d6d';
const dCol   = d => d === 'BUY' ? '#00d97e' : d === 'SELL' ? '#ff4d6d' : '#8892a4';
const dBg    = d => d === 'BUY' ? 'rgba(0,217,126,.13)' : d === 'SELL' ? 'rgba(255,77,109,.13)' : 'rgba(136,146,164,.09)';
const dArrow = d => d === 'BUY' ? '&#9650;' : d === 'SELL' ? '&#9660;' : '&#9654;';
const dTxt   = d => d || 'WAIT';
const hCol   = hitRate >= 55 ? '#00d97e' : hitRate >= 0 ? '#ff4d6d' : '#8892a4';

const regLabel = reg => {
  const m = {
    'BULL_TREND_STRONG':'Bull Strong','BULL_TREND_WEAK':'Bull Weak',
    'BEAR_TREND_STRONG':'Bear Strong','BEAR_TREND_WEAK':'Bear Weak',
    'RANGING':'Ranging','CHOPPY':'Choppy','EXTREME_CAUTION':'Caution',
    'BREAKOUT':'Breakout','ACCUMULATION':'Accumulation','DISTRIBUTION':'Distribution',
  };
  return m[reg] || reg || '&mdash;';
};
const regColor = reg => {
  if (!reg) return '#8892a4';
  if (reg.includes('BULL') || reg === 'BREAKOUT' || reg === 'ACCUMULATION') return '#00d97e';
  if (reg.includes('BEAR') || reg === 'DISTRIBUTION') return '#ff4d6d';
  if (reg === 'EXTREME_CAUTION') return '#f59e0b';
  return '#8892a4';
};

const gaugeArc = pct => {
  const rr = 54, cx = 70, cy = 70;
  const end = Math.PI + (pct / 100) * Math.PI;
  const x2  = (cx + rr * Math.cos(end)).toFixed(1);
  const y2  = (cy + rr * Math.sin(end)).toFixed(1);
  return `M 16.0 70.0 A 54 54 0 ${pct > 50 ? 1 : 0} 1 ${x2} ${y2}`;
};

const sigRows = signals.map((s, i) => `
<tr class="sig-row" style="animation-delay:${i * 0.04}s">
  <td class="ts">${s.ts}</td>
  <td><span class="dir-chip" style="color:${dCol(s.dir)};background:${dBg(s.dir)}">${dArrow(s.dir)}&nbsp;${dTxt(s.dir)}</span></td>
  <td class="mono">$${parseInt(s.px||0).toLocaleString('en-US')}</td>
  <td>
    <div class="cpill">
      <div class="cfill" style="width:${s.conf}%;background:${dCol(s.dir)}40"></div>
      <div class="cfill-glow" style="width:${s.conf}%;background:${dCol(s.dir)}"></div>
      <span class="cnum">${s.conf}%</span>
    </div>
  </td>
  <td class="rsi-td mono"><span class="tip" data-tip="RSI below 30=oversold | above 70=overbought | ~50=neutral">${s.rsi}</span></td>
  <td style="color:${regColor(s.reg)};font-weight:600">${regLabel(s.reg)}</td>
</tr>`).join('') || `<tr><td colspan="6" class="empty-td">No signals yet &mdash; workflow runs every 5 min</td></tr>`;

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta http-equiv="refresh" content="300">
<title>Crypto Specialist v3</title>
<style>
:root{
  --bg:#04070d;--s1:#0a1018;--s2:#0f1724;--bdr:rgba(30,46,70,.85);--bdr2:rgba(44,64,95,.9);
  --txt:#dde6f0;--mut:#4e617a;--mut2:#6b80a0;
  --blu:#3b82f6;--cyn:#06b6d4;--grn:#00d97e;--red:#ff4d6d;--ylw:#f59e0b;--pur:#a855f7;
  --rad:14px;
}
*{box-sizing:border-box;margin:0;padding:0;-webkit-font-smoothing:antialiased}
html{overflow-y:scroll;background:var(--bg)}
body{color:var(--txt);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Inter",Helvetica,sans-serif;min-height:100vh}

/* Scanlines */
body::after{content:'';position:fixed;inset:0;z-index:6;pointer-events:none;
  background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,.022) 2px,rgba(0,0,0,.022) 4px)}

/* Sweeping scan line */
.scan-line{position:fixed;left:0;right:0;height:2px;z-index:7;pointer-events:none;
  background:linear-gradient(90deg,transparent 0%,rgba(0,217,126,.55) 40%,rgba(0,217,126,.55) 60%,transparent 100%);
  animation:scanDown 7s ease-in-out infinite;animation-delay:1.5s;opacity:0}
@keyframes scanDown{0%{top:-2px;opacity:0}3%{opacity:1}97%{opacity:.6}100%{top:100vh;opacity:0}}

/* Canvas layers */
#mc{position:fixed;inset:0;z-index:1;opacity:.24;pointer-events:none}
#gc{position:fixed;right:-50px;top:50%;transform:translateY(-50%);z-index:2;opacity:.21;pointer-events:none}
@media(max-width:900px){#gc{display:none}}

/* Header */
.hdr{display:flex;align-items:center;justify-content:space-between;
  padding:13px 28px;background:rgba(4,7,13,.85);border-bottom:1px solid var(--bdr);
  backdrop-filter:blur(22px);-webkit-backdrop-filter:blur(22px);
  position:sticky;top:0;z-index:200}
.hdr-l{display:flex;align-items:center;gap:14px}
.logo{font-size:1.05rem;font-weight:800;letter-spacing:-.02em;color:var(--txt)}
.logo-accent{color:var(--blu)}
.live-pill{display:flex;align-items:center;gap:5px;background:rgba(0,217,126,.08);
  border:1px solid rgba(0,217,126,.28);border-radius:20px;padding:3px 11px;
  font-size:.7rem;font-weight:700;color:var(--grn);letter-spacing:.06em}
.ldot{width:6px;height:6px;background:var(--grn);border-radius:50%;animation:ldot 1.8s ease-in-out infinite}
@keyframes ldot{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.25;transform:scale(.65)}}
.hdr-r{font-size:.73rem;color:var(--mut);display:flex;align-items:center;gap:10px}
.paper-badge{background:rgba(245,158,11,.1);border:1px solid rgba(245,158,11,.28);
  border-radius:6px;padding:3px 8px;color:var(--ylw);font-weight:700;font-size:.68rem;letter-spacing:.06em}

/* Layout */
.wrap{padding:20px 28px 28px;max-width:1440px;margin:0 auto;position:relative;z-index:10}
.mb12{margin-bottom:12px}

/* Cards - glassmorphism */
.card{background:rgba(15,23,36,.88);border:1px solid var(--bdr);border-radius:var(--rad);
  position:relative;overflow:hidden;
  backdrop-filter:blur(10px);-webkit-backdrop-filter:blur(10px);
  transition:border-color .25s,box-shadow .25s,transform .2s}
.card:hover{border-color:var(--bdr2);box-shadow:0 8px 40px rgba(0,0,0,.5);transform:translateY(-1px)}
.card::after{content:'';position:absolute;inset:0;border-radius:var(--rad);
  background:linear-gradient(135deg,rgba(255,255,255,.016) 0%,transparent 55%);pointer-events:none}

/* KPI Grid */
.kpi-grid{display:grid;grid-template-columns:2fr 1.4fr 1.2fr 1.1fr;gap:12px;margin-bottom:12px}
@media(max-width:860px){.kpi-grid{grid-template-columns:1fr 1fr}}
@media(max-width:500px){.kpi-grid{grid-template-columns:1fr}}
.kp{padding:20px 22px}
.kp-lbl{font-size:.66rem;color:var(--mut);text-transform:uppercase;letter-spacing:.09em;margin-bottom:10px;cursor:default}
.kp-val{font-size:2rem;font-weight:900;line-height:1;letter-spacing:-.03em;margin-bottom:8px}
.kp-sub{font-size:.76rem;color:var(--mut2);display:flex;align-items:center;gap:8px;flex-wrap:wrap}
.price-card .kp-val{font-size:2.5rem}
.delta{font-size:.95rem;font-weight:700;margin-left:6px}
.gblob{position:absolute;width:170px;height:170px;border-radius:50%;filter:blur(55px);opacity:.08;pointer-events:none;top:-50px;right:-50px}

/* Price card animated glow border */
@keyframes priceGlow{0%,100%{border-color:var(--bdr)}50%{border-color:${pCol}44;box-shadow:0 0 24px ${pCol}18}}
.price-card{animation:priceGlow 4s ease-in-out infinite}

/* Range Bar */
.range-card{padding:16px 22px;margin-bottom:12px}
.range-lbl{font-size:.66rem;color:var(--mut);text-transform:uppercase;letter-spacing:.09em;margin-bottom:12px}
.rbar-wrap{position:relative;height:8px;background:var(--s1);border-radius:4px;margin:0 4px}
@keyframes shimmer{0%{background-position:-300px 0}100%{background-position:300px 0}}
.rbar-fill{position:absolute;left:0;top:0;height:100%;border-radius:4px;
  background:linear-gradient(90deg,var(--blu),var(--cyn),var(--blu));
  background-size:300px 100%;animation:shimmer 2.5s linear infinite}
.rbar-thumb{position:absolute;top:50%;transform:translate(-50%,-50%);
  width:16px;height:16px;border-radius:50%;background:white;border:3px solid var(--bg);
  box-shadow:0 0 12px rgba(255,255,255,.35),0 2px 8px rgba(0,0,0,.4)}
.rbar-labels{display:flex;justify-content:space-between;align-items:center;margin-top:10px;font-size:.76rem}
.rmeta{display:flex;gap:18px;margin-top:12px;flex-wrap:wrap;font-size:.76rem;color:var(--mut2)}
.rmeta-item{display:flex;align-items:center;gap:5px}
.rmdot{width:5px;height:5px;border-radius:50%;background:var(--bdr2)}

/* Mid Grid */
.mid-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:12px}
@media(max-width:700px){.mid-grid{grid-template-columns:1fr}}
.dir-card{display:flex;flex-direction:column;padding:22px}
.dir-big{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:12px 0 16px}
.dir-icon{font-size:3.5rem;line-height:1;margin-bottom:10px}
.dir-txt{font-size:2rem;font-weight:900;letter-spacing:.06em}
@keyframes neonPulse{0%,100%{text-shadow:none}50%{text-shadow:0 0 18px currentColor,0 0 36px currentColor,0 0 60px currentColor}}
.dir-txt{animation:neonPulse 3s ease-in-out infinite}
.dir-meta{font-size:.73rem;color:var(--mut2);margin-top:8px;text-align:center;line-height:1.5}
.dir-pills{display:flex;gap:8px;margin-top:12px}
.dir-pill{flex:1;background:rgba(4,7,13,.7);border:1px solid var(--bdr);border-radius:9px;padding:9px 8px;text-align:center}
.dp-lbl{font-size:.62rem;color:var(--mut);text-transform:uppercase;letter-spacing:.07em;margin-bottom:4px}
.dp-val{font-size:1.1rem;font-weight:800}

/* Gauge */
.gauge-card{display:flex;flex-direction:column;padding:22px;align-items:center}
.gauge-wrap{position:relative;margin:8px 0 4px}
.gauge-wrap svg{display:block}
.gauge-num{position:absolute;bottom:4px;left:50%;transform:translateX(-50%);font-size:1.6rem;font-weight:900;text-align:center;white-space:nowrap}
.gauge-caption{font-size:.7rem;color:var(--mut);text-align:center;margin-bottom:12px}
.gauge-threshold{display:flex;align-items:center;justify-content:center;gap:6px;font-size:.72rem;padding:6px 12px;border-radius:8px;background:rgba(4,7,13,.7);border:1px solid var(--bdr)}

/* Ring */
.ring-card{display:flex;flex-direction:column;padding:22px;align-items:center}
.ring-wrap{position:relative;margin:4px 0 12px}
.ring-wrap svg{display:block;transform:rotate(-90deg)}
.ring-num{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:1.2rem;font-weight:900}
.ring-lbl{font-size:.73rem;color:var(--mut2);text-align:center;line-height:1.6}

/* Table */
.sec-hdr{font-size:.7rem;font-weight:700;color:var(--mut2);text-transform:uppercase;letter-spacing:.09em;
  margin-bottom:10px;display:flex;align-items:center;gap:10px}
.sec-hdr::after{content:'';flex:1;height:1px;background:var(--bdr)}
table{width:100%;border-collapse:collapse;background:rgba(15,23,36,.88);
  border:1px solid var(--bdr);border-radius:var(--rad);overflow:hidden;
  backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px)}
thead{background:rgba(10,16,24,.92)}
th{padding:10px 16px;text-align:left;font-size:.65rem;color:var(--mut);text-transform:uppercase;letter-spacing:.08em;font-weight:600;white-space:nowrap}
td{padding:11px 16px;border-top:1px solid rgba(30,46,70,.5);font-size:.83rem;vertical-align:middle}
@keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
.sig-row{animation:fadeUp .35s ease both;transition:background .15s}
.sig-row:hover td{background:rgba(255,255,255,.022)}
.ts{color:var(--mut2);font-size:.74rem;font-variant-numeric:tabular-nums}
.mono{font-variant-numeric:tabular-nums}
.dir-chip{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;border-radius:7px;font-size:.74rem;font-weight:700;letter-spacing:.06em}
.empty-td{text-align:center;color:var(--mut);padding:36px;font-style:italic;font-size:.85rem}
.cpill{position:relative;background:rgba(4,7,13,.7);border-radius:5px;height:20px;width:90px;overflow:hidden}
.cfill{position:absolute;left:0;top:0;height:100%;border-radius:5px}
.cfill-glow{position:absolute;left:0;bottom:0;height:2px;border-radius:1px}
.cnum{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:.7rem;font-weight:700;z-index:1}

/* Tooltips */
.tip{position:relative;cursor:help;border-bottom:1px dashed var(--bdr2)}
.tip::after{content:attr(data-tip);display:none;position:absolute;bottom:calc(100% + 8px);left:50%;transform:translateX(-50%);
  background:#1a2840;border:1px solid var(--bdr2);border-radius:9px;padding:9px 13px;font-size:.71rem;color:var(--txt);
  white-space:normal;min-width:180px;max-width:260px;line-height:1.45;z-index:999;box-shadow:0 6px 24px rgba(0,0,0,.7);
  pointer-events:none;font-style:normal;font-weight:400}
.tip:hover::after{display:block}

/* Footer */
.footer{text-align:center;font-size:.71rem;color:var(--mut);padding:16px 28px 20px;
  border-top:1px solid var(--bdr);margin-top:8px;
  background:rgba(4,7,13,.85);backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);
  line-height:1.7;position:relative;z-index:10}
.footer a{color:var(--blu);text-decoration:none}
.footer a:hover{text-decoration:underline}

/* Entry animations */
.kpi-grid>*:nth-child(1){animation:fadeUp .5s .05s ease both}
.kpi-grid>*:nth-child(2){animation:fadeUp .5s .10s ease both}
.kpi-grid>*:nth-child(3){animation:fadeUp .5s .15s ease both}
.kpi-grid>*:nth-child(4){animation:fadeUp .5s .20s ease both}
.range-card{animation:fadeUp .5s .25s ease both}
.mid-grid>*:nth-child(1){animation:fadeUp .5s .30s ease both}
.mid-grid>*:nth-child(2){animation:fadeUp .5s .34s ease both}
.mid-grid>*:nth-child(3){animation:fadeUp .5s .38s ease both}
table{animation:fadeUp .5s .44s ease both}
</style>
</head>
<body>
<div class="scan-line"></div>
<canvas id="mc"></canvas>
<canvas id="gc"></canvas>

<div class="hdr">
  <div class="hdr-l">
    <div class="logo">Crypto <span class="logo-accent">Specialist</span> v3</div>
    <div class="live-pill"><span class="ldot"></span> LIVE</div>
  </div>
  <div class="hdr-r">
    <span>${new Date().toISOString().slice(0,16).replace('T',' ')} UTC</span>
    <span>|</span><span>Auto-refresh 5min</span>
    <span>|</span><span class="paper-badge">PAPER MODE</span>
  </div>
</div>

<div class="wrap">
<div class="kpi-grid mb12">
  <div class="card price-card">
    <div class="gblob" style="background:${pCol}"></div>
    <div class="kp">
      <div class="kp-lbl"><span class="tip" data-tip="Bitcoin last trade price on Kraken spot exchange. Updates every 5 min.">BTC / USD</span></div>
      <div class="kp-val" style="color:${pCol}">$${fmt(price)}<span class="delta" style="color:${pCol}">${c24Str}</span></div>
      <div class="kp-sub">Open&nbsp;<strong>$${fmt(openDay)}</strong>&nbsp;|&nbsp;VWAP&nbsp;<strong>$${fmt(vwap24)}</strong></div>
    </div>
  </div>
  <div class="card">
    <div class="gblob" style="background:${dCol(last.dir||'WAIT')}"></div>
    <div class="kp">
      <div class="kp-lbl"><span class="tip" data-tip="Latest direction from 10-strategy quorum gate. WAIT = confidence below 60% or quorum failed.">Current Signal</span></div>
      <div class="kp-val" style="font-size:1.7rem;display:flex;align-items:center;gap:8px;color:${dCol(last.dir||'WAIT')}">
        <span style="font-size:1.4rem">${dArrow(last.dir||'WAIT')}</span><span>${dTxt(last.dir||'WAIT')}</span>
      </div>
      <div class="kp-sub">Conf:&nbsp;<strong style="color:${dCol(last.dir||'WAIT')}">${last.conf||'?'}%</strong>&nbsp;|&nbsp;${last.ts||'&mdash;'}&nbsp;UTC</div>
    </div>
  </div>
  <div class="card">
    <div class="kp">
      <div class="kp-lbl"><span class="tip" data-tip="% of BUY/SELL signals where BTC moved >0.3% correctly. Updated every 4h. Need 55%+ for live trading.">Hit Rate</span></div>
      <div class="kp-val" style="color:${hCol}">${hitRate >= 0 ? hitRate + '%' : 'N/A'}</div>
      <div class="kp-sub">${hitTotal > 0 ? '<span style="color:var(--grn)">' + hitCorrect + '&nbsp;W</span>&nbsp;/&nbsp;<span style="color:var(--red)">' + hitIncorrect + '&nbsp;L</span>&nbsp;of&nbsp;' + hitTotal : '<em>Accumulating...</em>'}${hitAvgConf > 0 ? '&nbsp;|&nbsp;Avg&nbsp;' + hitAvgConf + '%' : ''}</div>
    </div>
  </div>
  <div class="card">
    <div class="kp">
      <div class="kp-lbl"><span class="tip" data-tip="Market regime from Hurst exponent, ATR and trend strength. Drives strategy weights and confidence multipliers.">Market Regime</span></div>
      <div class="kp-val" style="font-size:1.05rem;margin-top:4px;line-height:1.5;font-weight:800;color:${regColor(last.reg||'')}">${regLabel(last.reg||'')}</div>
      <div class="kp-sub">${last.quor && last.quor !== '?' ? 'Quorum:&nbsp;<strong>' + last.quor + '/10</strong>&nbsp;families' : 'Market structure class'}</div>
    </div>
  </div>
</div>

<div class="card range-card mb12">
  <div class="range-lbl"><span class="tip" data-tip="Current price position within today's 24H high/low range. The white marker is the live price.">24H Price Range</span></div>
  <div class="rbar-wrap">
    <div class="rbar-fill" style="width:${rangePos}%"></div>
    <div class="rbar-thumb" style="left:${rangePos}%"></div>
  </div>
  <div class="rbar-labels">
